sys_script_include.script:
var ProactiveIncidentCreator = Class.create();

ProactiveIncidentCreator.prototype = {

    initialize: function() {
        this.log = new GSLog('u_anomaly.log.level', 'ProactiveIncidentCreator');
    },

    /**
     * Create an incident for the given anomaly event, if not already present.
     * @param {GlideRecord} anomalyEvent - u_anomaly_event GlideRecord
     * @returns {String|null} - Incident sys_id or null if skipped
     */
    createForAnomalyEvent: function(anomalyEvent) {
        var ciSysId = anomalyEvent.u_configuration_item.toString();
        var state   = parseInt(anomalyEvent.u_state.toString());

        // Only trigger for Degraded (3) or higher
        if (state < 3) {
            this.log.logInfo('createForAnomalyEvent | State ' + state + ' below threshold. Skipping.');
            return null;
        }

        // Duplicate check
        if (this._hasOpenIncident(ciSysId)) {
            this.log.logInfo('createForAnomalyEvent | Open incident already exists for CI ' + ciSysId + '. Skipping.');
            return null;
        }

        var priority = (state >= 4) ? 1 : 2; // Outage=P1, Degraded=P2
        var ciName   = anomalyEvent.u_configuration_item.getDisplayValue();

        var inc = new GlideRecord('incident');
        inc.initialize();
        inc.short_description  = 'Proactive Alert: ' + ciName + ' — Service ' + this._stateLabel(state) + ' Detected';
        inc.description        = 'Automatically generated by ProactiveIncidentCreator.\n' +
                                 'Anomaly Event: ' + anomalyEvent.number.toString() + '\n' +
                                 'CI: ' + ciName + '\n' +
                                 'Detected On: ' + anomalyEvent.u_detected_on.getDisplayValue() + '\n' +
                                 'Signal Count: ' + anomalyEvent.u_signal_count.toString();
        inc.cmdb_ci            = ciSysId;
        inc.priority           = priority;
        inc.impact             = 1;
        inc.urgency            = priority;
        inc.category           = 'software';
        inc.subcategory        = 'performance';
        inc.caller_id          = gs.getUserID();
        inc.u_anomaly_event    = anomalyEvent.sys_id.toString();
        inc.u_proactive_alert  = true;

        var sysId = inc.insert();
        this.log.logInfo('createForAnomalyEvent | Incident created: ' + inc.number +
            ' | Priority: P' + priority + ' | CI: ' + ciName);
        return sysId;
    },

    _hasOpenIncident: function(ciSysId) {
        var gr = new GlideRecord('incident');
        gr.addQuery('cmdb_ci', ciSysId);
        gr.addQuery('priority', 'IN', '1,2');
        gr.addQuery('state', 'NOT IN', '6,7'); // Not resolved/closed
        gr.setLimit(1);
        gr.query();
        return gr.hasNext();
    },

    _stateLabel: function(state) {
        var labels = { 1: 'Normal', 2: 'Anomalous', 3: 'Degraded', 4: 'Outage' };
        return labels[state] || 'Unknown';
    },

    type: 'ProactiveIncidentCreator'
};
